// ─── JD utilities ─────────────────────────────────────────────
function _jdFromDate(dd: number, mm: number, yy: number): number {
  const a = Math.floor((14 - mm) / 12);
  const y = yy + 4800 - a;
  const m = mm + 12 * a - 3;
  let jd = dd + Math.floor((153*m+2)/5) + 365*y + Math.floor(y/4) - Math.floor(y/100) + Math.floor(y/400) - 32045;
  if (jd < 2299161) jd = dd + Math.floor((153*m+2)/5) + 365*y + Math.floor(y/4) - 32083;
  return jd;
}

function _dateDiff(y1:number,m1:number,d1:number, y2:number,m2:number,d2:number): number {
  function toJD(y:number,m:number,d:number): number {
    const a=Math.floor((14-m)/12), yy=y+4800-a, mm=m+12*a-3;
    let jd=d+Math.floor((153*mm+2)/5)+365*yy+Math.floor(yy/4)-Math.floor(yy/100)+Math.floor(yy/400)-32045;
    if(jd<2299161) jd=d+Math.floor((153*mm+2)/5)+365*yy+Math.floor(yy/4)-32083;
    return jd;
  }
  return toJD(y2,m2,d2) - toJD(y1,m1,d1);
}

// ─── Solar → Lunar ────────────────────────────────────────────
export function solarToLunar(dd: number, mm: number, yy: number): { day: number; month: number; year: number; isLeap: boolean } {
  const target = yy*10000 + mm*100 + dd;
  let lo=0, hi=_LUNAR_TABLE.length-1, idx=-1;
  while (lo <= hi) {
    const mid = (lo+hi)>>1;
    if (_LUNAR_TABLE[mid]![0] <= target) { idx=mid; lo=mid+1; }
    else hi=mid-1;
  }
  if (idx < 0) return { day:1, month:1, year:yy, isLeap:false };
  const [sk,lm,leap,ly] = _LUNAR_TABLE[idx]!;
  const sy=Math.floor(sk/10000), sm=Math.floor(sk/100)%100, sd=sk%100;
  const lunarDay = _dateDiff(sy,sm,sd, yy,mm,dd) + 1;
  return { day:lunarDay, month:lm, year:ly, isLeap: leap===1 };
}

// ─── Can Chi helpers ──────────────────────────────────────────
export function hourToChi(hour: number): DiaChi {
  return _CHI[Math.floor((hour + 1) / 2) % 12]!;
}

export function yearCanChi(year: number): string {
  return _CAN[(year + 6) % 10]! + ' ' + _CHI[(year + 8) % 12]!;
}

export function dayCanChi(dd: number, mm: number, yy: number): string {
  const jd = _jdFromDate(dd, mm, yy);
  return _CAN[(jd + 9) % 10]! + ' ' + _CHI[(jd + 1) % 12]!;
}

export function hourCanChi(hour: number, dayCanStr: string): string {
  const chiIndex = Math.floor((hour + 1) / 2) % 12;
  const canIndex = (_CAN.indexOf(dayCanStr.split(' ')[0]! as ThienCan) * 2 + chiIndex) % 10;
  return _CAN[canIndex]! + ' ' + _CHI[chiIndex]!;
}

// ─── Main converter ───────────────────────────────────────────
export function convertDuongToAm(dd: number, mm: number, yy: number, hour: number): ConvertDuongToAmResult & {
  canChi: { year: string; day: string; hour: string };
  gioChi: DiaChi;
  amDuongNam: AmDuong;
} {
  const rawLich = solarToLunar(dd, mm, yy);
  const amLich = { ngayAL: rawLich.day, thangAL: rawLich.month, namAL: rawLich.year, isLeap: rawLich.isLeap };
  const gioChi = hourToChi(hour);
  const gioIdx = _CHI.indexOf(gioChi);
  const namCanChi  = yearCanChi(amLich.namAL);
  const ngayCanChi = dayCanChi(dd, mm, yy);
  const gioCanChi  = hourCanChi(hour, ngayCanChi);
  const canNam = namCanChi.split(' ')[0]! as ThienCan;
  const chiNam = namCanChi.split(' ')[1]! as DiaChi;
  const _DUONG_CAN = new Set<ThienCan>(['Giáp','Bính','Mậu','Canh','Nhâm']);
  const amDuongNam: AmDuong = _DUONG_CAN.has(canNam) ? 'dương' : 'âm';
  return {
    amLich,
    canChi: { year: namCanChi, day: ngayCanChi, hour: gioCanChi },
    gioChi,
    gioIdx,
    canNam,
    chiNam,
    amDuongNam,
  };
}
